‘ t i m e s c a l e 1ns / 1ps
module alu (
input wire [ 2 : 0 ] op ,
input wire [ 7 : 0 ] num1,
output reg [ 3 1 : 0 ] r e s u l t
) ;
wire [ 3 1 : 0 ] num2;
wire [ 3 1 : 0 ] sign_extend_num1 ;
assign num2=32’h0000_0001 ;
assign sign_extend_num1={24’h0 ,num1};
always@ (*) begin
case (op)
3 ’ b000 : r e s u l t=sign_extend_num1+num2;
10
3 ’ b001 : r e s u l t=sign_extend_num1 -num2;
3 ’ b010 : r e s u l t=sign_extend_num1&num2;
3 ’ b011 : r e s u l t=sign_extend_num1 |num2;
3 ’ b100 : r e s u l t=~sign_extend_num1 ;
3 ’ b101 : begin
i f ( sign_extend_num1<num2) r e s u l t =32’h0000_0001 ;
e l s e r e s u l t =32’h0000_0000 ;
end
default : r e s u l t =32’hxxxx_xxxx ;
endcase
end
endmodule

