label("$A$",A,W);
label("$B$",B,E);
label("$C$",C,SW);
label("$D$",D,SE);
label("$E$",G,N);
label("$F$",F,N);
label("$O$",O,S);
draw(Circle(A,2));
draw(Circle(B,2));
